	Memory      string                 `json:"memory"`      // 内存资源
	GPU         string                 `json:"gpu"`         // GPU资源
	ProjectName string                 `json:"projectName"` // 项目名称
	WebURL      string                 `json:"webUrl"`      // WebIDE访问地址
