}

// Constants for dev machine status
const (
	StatusCreating         = "creating"         // 创建中
	StatusPending          = "pending"          // 排队中
	StatusTerminating      = "terminating"      // 关机中
	StatusCrashLoopBackOff = "crashloopbackoff" // 开机失败
	StatusRunning          = "running"          // 运行中
	StatusStopped          = "stopped"          // 已关机
	StatusError            = "error"            // 错误状态
	StatusUnknown          = "unknown"          // 未知状态
)

type StatusEnumProvider struct{}

var EnumItemMap = map[string]string{
	StatusCreating:         "创建中",
	StatusPending:          "排队中",
	StatusTerminating:      "关机中",
	StatusCrashLoopBackOff: "开机失败",
	StatusRunning:          "运行中",
	StatusStopped:          "已关机",
	StatusError:            "错误状态",
	StatusUnknown:          "未知状态",
}

func (p *StatusEnumProvider) GetEnum() []util.EnumItem {
	// 定义固定的顺序
	orderedKeys := []string{
		StatusCreating,
		StatusPending,
		StatusTerminating,
		StatusCrashLoopBackOff,
		StatusRunning,
		StatusStopped,
		StatusError,
		StatusUnknown,
	}
	enumItems := make([]util.EnumItem, 0, len(orderedKeys))
	for _, key := range orderedKeys {
		if value, exists := EnumItemMap[key]; exists {
			enumItems = append(enumItems, util.EnumItem{
				Key:   key,
				Value: value,
			})
		}
	}
	return enumItems
}

package devmachines

import (
	"time"

	"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/models"
	"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/util"
)

// Constants for IDE types
const (
	IDETypeVSCode  = "vscode"
	IDETypeJupyter = "jupyter"
)

// DevMachine represents a development machine instance
type DevMachine struct {
	CreateDevMachineRequest
	// Status information
	GPUDisplayname string `json:"gpuDisplayName"`
	Status         string `json:"status"`    // creating/running/stopped/error
	PodStatus      string `json:"podStatus"` // Kubernetes pod status
	PodName        string `json:"podName"`
	NodeName       string `json:"nodeName"`
	UserName       string `json:"creator"`
	Age            string `json:"age"`
	ClusterName    string `json:"clusterName"`
	WebURL         string `json:"webUrl,omitempty"`
	// SSHEndpoint   string    `json:"sshEndpoint,omitempty"`
	CreatedAt   string `json:"createdAt"`
	LastUpdated string `json:"lastUpdated"`
}

// ResourceUsage represents current resource usage of dev machine
type ResourceUsage struct {
	CPU    string `json:"cpu"`    // e.g., "1.2/2 cores"
	Memory string `json:"memory"` // e.g., "3.1/4 GiB"
	GPU    string `json:"gpu"`    // e.g., "0.8/1"
}

// DevMachineStatus represents detailed status of dev machine
type DevMachineStatus struct {
	DevMachine    `json:",inline"`
	ResourceUsage ResourceUsage `json:"resourceUsage"`
}

// DevMachineList represents a list of dev machines with pagination
type DevMachineList struct {
	Total int64        `json:"total"`
	Page  int32        `json:"page"`
	Data  []DevMachine `json:"data"`
}

// CreateDevMachineRequest represents request parameters for creating a dev machine
type CreateDevMachineRequest struct {
	Namespace       string                 `json:"namespace"`
	ClusterCode     string                 `json:"clusterCode" validate:"required"`
	ProjectId       uint64                 `uri:"projectId"`
	ProjectName     string                 `json:"projectName"`
	Name            string                 `json:"name" validate:"required"`
	Id              uint64                 `uri:"id" validate:"required"`
	QueueName       string                 `json:"queueName"`
	UserUid         string                 `json:"userUid" validate:"required"`
	Describe        string                 `json:"describe"`
	ImageConfig     models.ImageConfig     `json:"imageConfig"`
	Image           string                 `json:"image" validate:"required"`
	CPU             string                 `json:"cpu" validate:"required,min=1"`
	Memory          string                 `json:"memory" validate:"required,min=1"`
	GPU             string                 `json:"gpu" validate:"min=0"`
	GPUName         string                 `json:"gpuName"`                        // gpu资源名称
	GPUType         string                 `json:"gpuType" validate:"oneof=0 1 2"` // 0: 默认值 1：物理卡  2： 虚拟卡
	WebIDE          string                 `json:"webIDE" validate:"oneof=vscode jupyter"`
	Storage         []models.StorageConfig `json:"storage"`
	EnvironmentVars map[string]string      `json:"environmentVars"`
	Annotations     map[string]string      `json:"annotations"`
	Labels          map[string]string      `json:"labels"`
}

// UpdateDevMachineRequest represents request parameters for updating a dev machine
type UpdateDevMachineRequest struct {
	CreateDevMachineRequest `json:",inline"`
}

// DevMachineRequest represents request parameters for getting a dev machine
// use Delete、Get、Stop、Start DevMachine
type DevMachineRequest struct {
	ClusterCode string `form:"clusterCode" validate:"required"`
	ProjectId   uint64 `uri:"projectId"  validate:"required"`
	Id          uint64 `uri:"id"`
	Name        string `uri:"name"`
}

// ListDevMachinesRequest represents request parameters for listing dev machines
type ListDevMachinesRequest struct {
	ClusterCode string `form:"clusterCode" validate:"required"`
	ProjectId   uint64 `uri:"projectId"`
	UserUid     string `form:"userUid"`
	Creator     string `form:"creator"`
	ProjectName string `form:"projectName"`
	Name        string `form:"name"`
	QueueName   string `form:"queueName"`
	Status      string `form:"status"`
	Current     int    `form:"current"`
	Size        int    `form:"size"`
	// LabelSelector string `json:"labelSelector"`
}

// CreateDevMachineResponse represents response for create dev machine API
type CreateDevMachineResponse struct {
	Name        string `json:"name"`
	Status      string `json:"status"`
	WebURL      string `json:"webUrl,omitempty"`
	SSHEndpoint string `json:"sshEndpoint,omitempty"`
	CreatedAt   string `json:"createdAt"`
}

// UpdateDevMachineResponse represents response for update dev machine API
type UpdateDevMachineResponse struct {
	UpdatedAt time.Time `json:"updatedAt"`
}

// DeleteDevMachineResponse represents response for delete dev machine API
type DeleteDevMachineResponse struct {
	DeletedAt time.Time `json:"deletedAt"`
}

// StartDevMachineResponse represents response for start dev machine API
type StartDevMachineResponse struct {
	Status    string    `json:"status"`
	UpdatedAt time.Time `json:"updatedAt"`
}

// StopDevMachineResponse represents response for stop dev machine API
type StopDevMachineResponse struct {
	Status    string    `json:"status"`
	UpdatedAt time.Time `json:"updatedAt"`
}

// DevMachineStatusResponse represents response for get dev machine status API
type DevMachineStatusResponse struct {
	DevMachine
	ResourceUsage ResourceUsage `json:"resourceUsage"`
	//Endpoints     DevMachineEndpoints `json:"endpoints"`
}

// ListDevMachineResponse represents the response for listing dev machines
type ListDevMachineResponse struct {
	Total int64                `json:"total"`
	Items []DevMachineListItem `json:"data"`
}

// DevMachineListItem represents a single item in the dev machine list
type DevMachineListItem struct {
	Id          uint64                 `json:"id"`
	Name        string                 `json:"name"`        // 开发机名称
	Status      string                 `json:"status"`      // 状态
	ClusterCode string                 `json:"clusterCode"` // 集群
	ClusterName string                 `json:"clusterName"` // 集群名称
	QueueName   string                 `json:"queueName"`   // 队列名称
	CPU         string                 `json:"cpu"`         // CPU资源

