// LifecycleStageInfo describes the current pod lifecycle stage of a dev machine.
// It is more granular than Status and covers every phase a pod goes through:
// Scheduling → PullingImage → Initializing → Starting → Running.
type LifecycleStageInfo struct {
	Stage   string `json:"stage"`   // 当前阶段，取值见 Stage* 常量
	Healthy bool   `json:"healthy"` // 是否在正常推进（false 表示卡住或报错）
	Reason  string `json:"reason"`  // K8s 原始 reason code，失败时有值
	Message string `json:"message"` // 人可读的描述
}

