// isImagePullError 判断 waiting reason 是否为镜像拉取失败
func isImagePullError(reason string) bool {
	return reason == "ImagePullBackOff" || reason == "ErrImagePull"
}

// computeLifecycleStage 根据 Pod 当前状态计算精细的生命周期阶段。
// Pod 正常生命周期：调度(Scheduling) → 拉取镜像(PullingImage) → InitContainer(Initializing) → 业务容器启动(Starting) → 运行(Running)
// 每个阶段都可能因不同原因失败，healthy=false 表示该阶段出现异常。
func computeLifecycleStage(pod *corev1.Pod) devmachines.LifecycleStageInfo {
	// 1. Pod 正在被删除
	if pod.DeletionTimestamp != nil {
		return devmachines.LifecycleStageInfo{
			Stage:   devmachines.StageTerminating,
			Healthy: true,
			Message: "Pod 正在终止",
		}
	}

	switch pod.Status.Phase {
	case corev1.PodPending:
		return computePendingStage(pod)

	case corev1.PodRunning:
		return computeRunningStage(pod)

	case corev1.PodSucceeded:
		return devmachines.LifecycleStageInfo{
			Stage:   devmachines.StageStopped,
			Healthy: true,
			Message: "Pod 已正常退出",
		}

	case corev1.PodFailed:
		reason, message := podFailureInfo(pod)
		return devmachines.LifecycleStageInfo{
			Stage:   devmachines.StageFailed,
			Healthy: false,
			Reason:  reason,
			Message: message,
		}

	default:
		return devmachines.LifecycleStageInfo{
			Stage:   devmachines.StageScheduling,
			Healthy: false,
			Reason:  "Unknown",
			Message: "Pod 状态未知",
		}
	}
}

// computePendingStage 处理 Pod Phase 为 Pending 时的阶段判断。
// Pending 可能处于：等待调度、拉取镜像、启动 InitContainer、启动业务容器 等子阶段。
func computePendingStage(pod *corev1.Pod) devmachines.LifecycleStageInfo {
	// 检查调度条件：PodScheduled=False 说明还未调度到节点
	for _, cond := range pod.Status.Conditions {
		if cond.Type == corev1.PodScheduled && cond.Status == corev1.ConditionFalse {
			return devmachines.LifecycleStageInfo{
				Stage:   devmachines.StageScheduling,
				Healthy: false,
				Reason:  cond.Reason,
				Message: cond.Message,
			}
		}
	}

	// 已调度到节点，检查 InitContainer 状态
	for _, cs := range pod.Status.InitContainerStatuses {
		if cs.State.Waiting != nil {
			reason := cs.State.Waiting.Reason
			msg := cs.State.Waiting.Message
			if isImagePullError(reason) {
				return devmachines.LifecycleStageInfo{
					Stage:   devmachines.StagePullingImage,
					Healthy: false,
					Reason:  reason,
					Message: fmt.Sprintf("InitContainer %s 镜像拉取失败: %s", cs.Name, msg),
				}
			}
			return devmachines.LifecycleStageInfo{
				Stage:   devmachines.StageInitializing,
				Healthy: reason == "PodInitializing" || reason == "ContainerCreating",
				Reason:  reason,
				Message: fmt.Sprintf("InitContainer %s 等待中: %s", cs.Name, msg),
			}
		}
		// InitContainer 运行中但尚未完成
		if cs.State.Running != nil && !cs.Ready {
			return devmachines.LifecycleStageInfo{
				Stage:   devmachines.StageInitializing,
				Healthy: true,
				Message: fmt.Sprintf("InitContainer %s 正在运行", cs.Name),
			}
		}
	}

	// 检查主容器等待状态
	for _, cs := range pod.Status.ContainerStatuses {
		if cs.State.Waiting != nil {
			reason := cs.State.Waiting.Reason
			msg := cs.State.Waiting.Message
			if isImagePullError(reason) {
				return devmachines.LifecycleStageInfo{
					Stage:   devmachines.StagePullingImage,
					Healthy: false,
					Reason:  reason,
					Message: fmt.Sprintf("容器 %s 镜像拉取失败: %s", cs.Name, msg),
				}
			}
			return devmachines.LifecycleStageInfo{
				Stage:   devmachines.StageStarting,
				Healthy: reason == "ContainerCreating" || reason == "PodInitializing",
				Reason:  reason,
				Message: fmt.Sprintf("容器 %s 等待中: %s", cs.Name, msg),
			}
		}
	}

	// Pod 已调度但无容器状态信息，正在准备中
	return devmachines.LifecycleStageInfo{
		Stage:   devmachines.StageScheduling,
		Healthy: true,
		Message: "Pod 已调度，正在准备容器",
	}
}

// computeRunningStage 处理 Pod Phase 为 Running 时的阶段判断。
// Running 阶段可能处于：InitContainer 收尾、业务容器启动、全部就绪 等子状态。
func computeRunningStage(pod *corev1.Pod) devmachines.LifecycleStageInfo {
	// 检查 InitContainer 是否仍在运行（Running phase 也可能有 init 未完成）
	for _, cs := range pod.Status.InitContainerStatuses {
		if !cs.Ready {
			if cs.State.Waiting != nil {
				reason := cs.State.Waiting.Reason
				if isImagePullError(reason) {
					return devmachines.LifecycleStageInfo{
						Stage:   devmachines.StagePullingImage,
						Healthy: false,
						Reason:  reason,
						Message: fmt.Sprintf("InitContainer %s 镜像拉取失败", cs.Name),
					}
				}
				return devmachines.LifecycleStageInfo{
					Stage:   devmachines.StageInitializing,
					Healthy: false,
					Reason:  reason,
					Message: fmt.Sprintf("InitContainer %s 异常: %s", cs.Name, cs.State.Waiting.Message),
				}
			}
			return devmachines.LifecycleStageInfo{
				Stage:   devmachines.StageInitializing,
				Healthy: true,
				Message: fmt.Sprintf("InitContainer %s 正在运行", cs.Name),
			}
		}
	}

	// 检查主容器就绪状态
	for _, cs := range pod.Status.ContainerStatuses {
		if cs.Ready {
			continue
		}
		if cs.State.Waiting != nil {
			reason := cs.State.Waiting.Reason
			msg := cs.State.Waiting.Message
			if isImagePullError(reason) {
				return devmachines.LifecycleStageInfo{
					Stage:   devmachines.StagePullingImage,
					Healthy: false,
					Reason:  reason,
					Message: fmt.Sprintf("容器 %s 镜像拉取失败: %s", cs.Name, msg),
				}
			}
			healthy := reason == "ContainerCreating" || reason == "PodInitializing"
			return devmachines.LifecycleStageInfo{
				Stage:   devmachines.StageStarting,
				Healthy: healthy,
				Reason:  reason,
				Message: fmt.Sprintf("容器 %s 启动中: %s", cs.Name, msg),
			}
		}
		// 容器未就绪且无等待原因，可能刚启动
		return devmachines.LifecycleStageInfo{
			Stage:   devmachines.StageStarting,
			Healthy: true,
			Message: fmt.Sprintf("容器 %s 正在启动，等待就绪", cs.Name),
		}
	}

	// 所有容器就绪
	return devmachines.LifecycleStageInfo{
		Stage:   devmachines.StageRunning,
		Healthy: true,
		Message: "所有容器正常运行",
	}
}

// podFailureInfo 从 Failed 的 Pod 中提取失败原因和消息
func podFailureInfo(pod *corev1.Pod) (reason, message string) {
	reason = pod.Status.Reason
	message = pod.Status.Message
	// 优先从容器状态中取更具体的错误
	for _, cs := range pod.Status.ContainerStatuses {
		if cs.State.Terminated != nil && cs.State.Terminated.ExitCode != 0 {
			if cs.State.Terminated.Reason != "" {
				reason = cs.State.Terminated.Reason
			}
			if cs.State.Terminated.Message != "" {
				message = fmt.Sprintf("容器 %s 异常退出(exit %d): %s", cs.Name, cs.State.Terminated.ExitCode, cs.State.Terminated.Message)
			} else {
				message = fmt.Sprintf("容器 %s 异常退出(exit %d)", cs.Name, cs.State.Terminated.ExitCode)
			}
			return
		}
		if cs.State.Waiting != nil && cs.State.Waiting.Reason == "CrashLoopBackOff" {
			reason = "CrashLoopBackOff"
			message = fmt.Sprintf("容器 %s 反复崩溃重启", cs.Name)
			return
		}
	}
	if message == "" {
		message = "Pod 运行失败"
	}
	return
}

