package controller

import (
	"context"
	"fmt"
	"strconv"
	"strings"
	"time"

	appsv1 "k8s.io/api/apps/v1"
	corev1 "k8s.io/api/core/v1"
	networkingv1 "k8s.io/api/networking/v1"
	"k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/apimachinery/pkg/api/resource"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/util/intstr"
	"k8s.io/utils/pointer"

	devmachines "code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/models/dev_machines"
)

const (
	devMachineLabel = "app.kubernetes.io/name=dev-machine"
	sshPort         = 22
	vscodePort      = 8080
	jupyterPort     = 8888
)

// CreateDevMachine creates a new development machine
func (c *Controller) CreateDevMachine(ctx context.Context, req *devmachines.CreateDevMachineRequest) (*devmachines.CreateDevMachineResponse, error) {
	// Check if machine already exists
	_, err := c.client.AppsV1().Deployments(req.Namespace).Get(ctx, req.Name, metav1.GetOptions{})
	if err == nil {
		return nil, fmt.Errorf("dev machine %s already exists", req.Name)
	}
	if !errors.IsNotFound(err) {
		return nil, err
	}

	// Create deployment
	// Create deployment with GPU resource if requested
	deployment := c.createDevMachineDeployment(req)
	if IsAscend910bDeployment(deployment) {
		if err := DeploymentAscendConfig(c.client, deployment); err != nil {
			return nil, err
		}
	}
	_, err = c.client.AppsV1().Deployments(req.Namespace).Create(ctx, deployment, metav1.CreateOptions{})
	if err != nil {
		return nil, err
	}

	// Create service
	service := c.createDevMachineService(req)
	service, err = c.client.CoreV1().Services(req.Namespace).Create(ctx, service, metav1.CreateOptions{})
	if err != nil {
		return nil, err
	}

	// Create ingress if WebIDE is enabled
	var webURL string
	if strings.TrimSpace(req.WebIDE) != "" {
		ingress := c.createDevMachineIngress(req)
		ingress, err = c.client.NetworkingV1().Ingresses(req.Namespace).Create(ctx, ingress, metav1.CreateOptions{})
		if err != nil {
			return nil, err
		}

		// Get ingress URLs
		if len(ingress.Spec.Rules) > 0 {
			switch req.WebIDE {
			case devmachines.IDETypeVSCode:
				webURL = fmt.Sprintf(c.ingressAddress+"/%s-%s/vscode", req.Namespace, req.Name)
			case devmachines.IDETypeJupyter:
				webURL = fmt.Sprintf(c.ingressAddress+"%s?token=my-token", ingress.Spec.Rules[0].IngressRuleValue.HTTP.Paths[0].Path)
			}
		}
	}

	return &devmachines.CreateDevMachineResponse{
		Name:        req.Name,
		Status:      devmachines.StatusCreating,
		WebURL:      webURL,
		SSHEndpoint: fmt.Sprintf("%s:%d", service.Spec.ClusterIP, sshPort),
		CreatedAt:   time.Now().Format("2006-01-02 15:04:05"),
	}, nil
}

// UpdateDevMachine updates an existing development machine
func (c *Controller) UpdateDevMachine(ctx context.Context, name, namespace string, req *devmachines.UpdateDevMachineRequest) (*devmachines.UpdateDevMachineResponse, error) {
	deployment, err := c.client.AppsV1().Deployments(namespace).Get(ctx, name, metav1.GetOptions{})
	if err != nil {
		if errors.IsNotFound(err) {
			return nil, fmt.Errorf("dev machine %s in namespace %s not found", name, namespace)
		}
		return nil, err
	}

	labels := c.getDevMachineLabels(&req.CreateDevMachineRequest)
	annotations := c.getDevMachineAnnotations(&req.CreateDevMachineRequest)
	deployment.Annotations = annotations
	deployment.Labels = labels
	if err := c.configureResources(deployment, &req.CreateDevMachineRequest); err != nil {
		return nil, err
	}
	deployment.Spec.Template.Annotations = annotations
	c.configureWebIDE(deployment, &req.CreateDevMachineRequest)
	c.configureEnvironmentVars(deployment, &req.CreateDevMachineRequest)
	c.configureStorage(deployment, &req.CreateDevMachineRequest)

	if deployment.Spec.Template.Spec.NodeSelector != nil {
		RemoveNodeSelectors(deployment.Spec.Template.Spec.NodeSelector)
	}

	if IsAscend910bDeployment(deployment) {
		if err := DeploymentAscendConfig(c.client, deployment); err != nil {
			return nil, err
		}
	}

	_, err = c.client.AppsV1().Deployments(namespace).Update(ctx, deployment, metav1.UpdateOptions{})
	if err != nil {
		return nil, err
	}

	return &devmachines.UpdateDevMachineResponse{
		UpdatedAt: time.Now(),
	}, nil
}

// DeleteDevMachine deletes a development machine
func (c *Controller) DeleteDevMachine(ctx context.Context, name, namespace string, req *devmachines.DevMachineRequest) (*devmachines.DeleteDevMachineResponse, error) {
	var err error
	// Delete deployment
	err = c.client.AppsV1().Deployments(namespace).Delete(ctx, name, metav1.DeleteOptions{})
	if err != nil && !errors.IsNotFound(err) {
		return nil, err
	}

	// Delete service
	err = c.client.CoreV1().Services(namespace).Delete(ctx, name, metav1.DeleteOptions{})
	if err != nil && !errors.IsNotFound(err) {
		return nil, err
	}

	// Delete ingress
	err = c.client.NetworkingV1().Ingresses(namespace).Delete(ctx, name, metav1.DeleteOptions{})
	if err != nil && !errors.IsNotFound(err) {
		return nil, err
	}
	return &devmachines.DeleteDevMachineResponse{
		DeletedAt: time.Now(),
	}, nil
}

// StartDevMachine starts a development machine
func (c *Controller) StartDevMachine(ctx context.Context, namespace, name string) (*devmachines.StartDevMachineResponse, error) {
	deployment, err := c.client.AppsV1().Deployments(namespace).Get(ctx, name, metav1.GetOptions{})
	if err != nil {
		return nil, err
	}

	var replicas int32 = 1
	deployment.Spec.Replicas = &replicas

	_, err = c.client.AppsV1().Deployments(namespace).Update(ctx, deployment, metav1.UpdateOptions{})
	if err != nil {
		return nil, err
	}

	return &devmachines.StartDevMachineResponse{
		Status:    devmachines.StatusRunning,
		UpdatedAt: time.Now(),
	}, nil
}

// StopDevMachine stops a development machine
func (c *Controller) StopDevMachine(ctx context.Context, namespace, name string) (*devmachines.StopDevMachineResponse, error) {
	deployment, err := c.client.AppsV1().Deployments(namespace).Get(ctx, name, metav1.GetOptions{})
	if err != nil {
		return nil, err
	}

	var replicas int32 = 0
	deployment.Spec.Replicas = &replicas

	_, err = c.client.AppsV1().Deployments(namespace).Update(ctx, deployment, metav1.UpdateOptions{})
	if err != nil {
		return nil, err
	}

	return &devmachines.StopDevMachineResponse{
		Status:    devmachines.StatusStopped,
		UpdatedAt: time.Now(),
	}, nil
}

// ListDevMachines lists all development machines in a namespace with pagination
func (c *Controller) ListDevMachines(ctx context.Context, req *devmachines.ListDevMachinesRequest) (*devmachines.DevMachineList, error) {
	// Use label selector if provided, otherwise use default
	labelSelector := devMachineLabel
	// if req.LabelSelector != "" {
	// 	labelSelector = req.LabelSelector
	// }

	deployments, err := c.client.AppsV1().Deployments(req.ProjectName).List(ctx, metav1.ListOptions{
		LabelSelector: labelSelector,
	})
	if err != nil {
		return nil, err
	}

	// Get all machines first
	var allMachines []devmachines.DevMachine
	for _, deployment := range deployments.Items {
		machine, err := c.convertDeploymentToDevMachine(&deployment)
		if err != nil {
			return nil, err
		}

		// Fetch additional information for each machine
		c.enrichDevMachineInfo(ctx, machine, deployment.Namespace, deployment.Name)
		allMachines = append(allMachines, *machine)
	}

	// Apply pagination
	totalCount := int64(len(allMachines))

	// Default values for pagination if not provided
	page := int32(1)
	pageSize := int32(10)

	if req.Current > 0 {
		page = int32(req.Current)
	}
	if req.Size > 0 && req.Size <= 100 {
		pageSize = int32(req.Size)
	}

	// Calculate start and end indices for the current page
	startIdx := (page - 1) * pageSize
	endIdx := startIdx + pageSize

	// Check bounds
	if startIdx >= int32(totalCount) {
		// Return empty page if start index is beyond total count
		return &devmachines.DevMachineList{
			Total: totalCount,
			Page:  page,
			Data:  []devmachines.DevMachine{},
		}, nil
	}

	if endIdx > int32(totalCount) {
		endIdx = int32(totalCount)
	}

	// Get the subset of machines for the current page
	pagedMachines := allMachines[startIdx:endIdx]

	return &devmachines.DevMachineList{
		Total: totalCount,
		Page:  page,
		Data:  pagedMachines,
	}, nil
}

// GetDevMachineStatus gets the status of a development machine
func (c *Controller) GetDevMachineStatus(ctx context.Context, namespace, name string) (*devmachines.DevMachineStatusResponse, error) {
	deployment, err := c.client.AppsV1().Deployments(namespace).Get(ctx, name, metav1.GetOptions{})
	if err != nil {
		return nil, err
	}

	machine, err := c.convertDeploymentToDevMachine(deployment)
	if err != nil {
		return nil, err
	}

	return &devmachines.DevMachineStatusResponse{
		DevMachine: *machine,
	}, nil
}

// createDevMachineDeployment creates a new deployment for the dev machine
func (c *Controller) createDevMachineDeployment(req *devmachines.CreateDevMachineRequest) *appsv1.Deployment {
	labels := c.getDevMachineLabels(req)
	annotations := c.getDevMachineAnnotations(req)
	container := c.createBaseContainer(req)
	podSpec := c.createPodSpec(container)
	podSpec.SchedulerName = "volcano"

	deployment := &appsv1.Deployment{
		ObjectMeta: metav1.ObjectMeta{
			Name:        req.Name,
			Namespace:   req.Namespace,
			Labels:      labels,
			Annotations: annotations,
		},
		Spec: appsv1.DeploymentSpec{
			Replicas: pointer.Int32(1),
			Selector: &metav1.LabelSelector{
				MatchLabels: labels,
			},
			Template: corev1.PodTemplateSpec{
				ObjectMeta: metav1.ObjectMeta{
					Labels:      labels,
					Annotations: annotations,
				},
				Spec: podSpec,
			},
		},
	}

	c.configureResources(deployment, req)
	c.configureWebIDE(deployment, req)
	c.configureEnvironmentVars(deployment, req)
	c.configureStorage(deployment, req)

	return deployment
}

// getDevMachineLabels returns the labels for the dev machine
func (c *Controller) getDevMachineLabels(req *devmachines.CreateDevMachineRequest) map[string]string {
	labels := map[string]string{
		"devmachine.tap.ai.com/name": req.Name,
		"tap.ai.com/project-id":      strconv.FormatUint(req.ProjectId, 10),
		"tap.ai.com/user-uid":        req.UserUid,
	}
