func (c *Controller) configureResources(deployment *appsv1.Deployment, req *devmachines.CreateDevMachineRequest) error {
	container := &deployment.Spec.Template.Spec.Containers[0]
	// 创建新的资源列表，只保留 CPU 和内存资源
	newLimits := corev1.ResourceList{}
	newRequests := corev1.ResourceList{}

	cpu, err := resource.ParseQuantity(req.CPU)
	if err != nil {
		return fmt.Errorf("invalid CPU quantity: %v", err)
	}
	newLimits[corev1.ResourceCPU] = cpu
	newRequests[corev1.ResourceCPU] = cpu
	memory, err := resource.ParseQuantity(req.Memory)
	if err != nil {
		return fmt.Errorf("invalid Memory quantity: %v", err)
	}
	newLimits[corev1.ResourceMemory] = memory
	newRequests[corev1.ResourceMemory] = memory

	if req.GPU != "" && req.GPUName != "" && req.GPUType != "" {
		// TODO：这里暂时只考虑整卡，后续需要支持虚拟卡
		// switch req.GPUType {
		// case "1":
		// 	// Add GPU resources
		// 	container.Resources.Limits[gpuResource] = gpuQuantity
		// 	container.Resources.Requests[gpuResource] = gpuQuantity
		// case "2":
		// default:
		//}
		gpuQuantity, err := resource.ParseQuantity(req.GPU)
		if err != nil {
			return fmt.Errorf("invalid GPU quantity: %v", err)
		}
		gpuResource := corev1.ResourceName(req.GPUName)
		if len(gpuResource) != 0 {
			newLimits[gpuResource] = gpuQuantity
			newRequests[gpuResource] = gpuQuantity
		}
	}
	container.Resources.Limits = newLimits
	container.Resources.Requests = newRequests
	return nil
}

