func (c *Controller) configureWebIDE(deployment *appsv1.Deployment, req *devmachines.CreateDevMachineRequest) {
	if strings.TrimSpace(req.WebIDE) == "" {
		return
	}

	container := &deployment.Spec.Template.Spec.Containers[0]
	currentPorts := container.Ports // 只保留实际使用的ports变量

	// 检查是否已经配置了相同的WebIDE
	if c.hasSameWebIDEAlreadyConfigured(container, req.WebIDE) {
		return
	}

	// 清除现有的WebIDE配置
	c.clearWebIDEConfig(deployment)

	// 配置新的WebIDE
	switch req.WebIDE {
	case devmachines.IDETypeVSCode:
		container.Command = []string{
			"/bin/bash", "-c",
			fmt.Sprintf("code-server --bind-addr=0.0.0.0:%d --auth none", vscodePort),
		}
		container.Ports = append(currentPorts, corev1.ContainerPort{
			Name:          "vscode",
			ContainerPort: vscodePort,
		})
	case devmachines.IDETypeJupyter:
		container.Command = []string{
			"/bin/bash", "-c",
			fmt.Sprintf("jupyter lab --ip=0.0.0.0 --port=8888 --allow-root --NotebookApp.token=my-token --ServerApp.base_url=/%s-%s", req.Namespace, req.Name),
		}
		container.Ports = append(currentPorts, corev1.ContainerPort{
			Name:          "jupyter",
			ContainerPort: jupyterPort,
		})
	}
}

// 清除现有的WebIDE配置
func (c *Controller) clearWebIDEConfig(deployment *appsv1.Deployment) {
	container := &deployment.Spec.Template.Spec.Containers[0]

	// 清除命令（只有当命令包含WebIDE相关命令时才清除）
	if len(container.Command) > 0 {
		commandStr := strings.Join(container.Command, " ")
		if strings.Contains(commandStr, "code-server") || strings.Contains(commandStr, "jupyter lab") {
			container.Command = nil
		}
	}

	// 清除相关端口
	newPorts := make([]corev1.ContainerPort, 0, len(container.Ports))
	for _, port := range container.Ports {
		if port.Name != "vscode" && port.Name != "jupyter" {
			newPorts = append(newPorts, port)
		}
	}
	container.Ports = newPorts
}

// 检查是否已经配置了相同的WebIDE
func (c *Controller) hasSameWebIDEAlreadyConfigured(container *corev1.Container, webIDE string) bool {
	if len(container.Command) == 0 {
		return false
	}

	commandStr := strings.Join(container.Command, " ")
	switch webIDE {
	case devmachines.IDETypeVSCode:
		return strings.Contains(commandStr, "code-server")
	case devmachines.IDETypeJupyter:
		return strings.Contains(commandStr, "jupyter lab")
	default:
		return false
	}
}

func (c *Controller) configureEnvironmentVars(deployment *appsv1.Deployment, req *devmachines.CreateDevMachineRequest) {
	if len(req.EnvironmentVars) == 0 {
		return
	}

	container := &deployment.Spec.Template.Spec.Containers[0]

	// 初始化环境变量切片（如果为nil）
	if container.Env == nil {
		container.Env = make([]corev1.EnvVar, 0, len(req.EnvironmentVars))
	}

	// 创建现有环境变量的映射以便快速查找
	existingVars := make(map[string]int)
	for i, env := range container.Env {
		existingVars[env.Name] = i
	}

	// 处理请求中的环境变量
	for name, value := range req.EnvironmentVars {
		if index, exists := existingVars[name]; exists {
			// 更新已存在的环境变量
			container.Env[index].Value = value
		} else {
			// 添加新的环境变量
			container.Env = append(container.Env, corev1.EnvVar{
				Name:  name,
				Value: value,
			})
		}
	}
}

// configureStorage configures storage-related resources for the deployment
func (c *Controller) configureStorage(deployment *appsv1.Deployment, req *devmachines.CreateDevMachineRequest) {
	if len(req.Storage) == 0 {
		return
	}
	container := &deployment.Spec.Template.Spec.Containers[0]
	volumes, volumeMounts := c.ConfigureStorageForContainer(container, req.Storage)
	deployment.Spec.Template.Spec.Volumes = volumes
	container.VolumeMounts = volumeMounts
}

func (c *Controller) createDevMachineService(req *devmachines.CreateDevMachineRequest) *corev1.Service {
	labels := c.getDevMachineLabels(req)

	service := &corev1.Service{
		ObjectMeta: metav1.ObjectMeta{
			Name:      req.Name,
			Namespace: req.Namespace,
			Labels:    labels,
		},
		Spec: corev1.ServiceSpec{
			Selector: labels,
			Ports: []corev1.ServicePort{
				{
					Name:       "ssh",
					Port:       sshPort,
					TargetPort: intstr.FromInt(sshPort),
				},
			},
		},
	}

	// Add WebIDE ports if enabled
	if strings.TrimSpace(req.WebIDE) != "" {
		if req.WebIDE == devmachines.IDETypeVSCode {
			service.Spec.Ports = append(service.Spec.Ports, corev1.ServicePort{
				Name:       "vscode",
				Port:       vscodePort,
				TargetPort: intstr.FromInt(vscodePort),
			})
		}
		if req.WebIDE == devmachines.IDETypeJupyter {
			service.Spec.Ports = append(service.Spec.Ports, corev1.ServicePort{
				Name:       "jupyter",
				Port:       jupyterPort,
				TargetPort: intstr.FromInt(jupyterPort),
			})
		}
	}

	return service
}

func (c *Controller) createDevMachineIngress(req *devmachines.CreateDevMachineRequest) *networkingv1.Ingress {
	// Create base ingress with labels
	ingress := c.createBaseIngress(req)

	// Add IDE-specific rules
	c.addVSCodeIngressRule(ingress, req)
	c.addJupyterIngressRule(ingress, req)

	return ingress
}

// createBaseIngress creates a new ingress with basic configuration
func (c *Controller) createBaseIngress(req *devmachines.CreateDevMachineRequest) *networkingv1.Ingress {
	labels := map[string]string{
		"app":                    req.Name,
		"app.kubernetes.io/name": "dev-machine",
	}
	for k, v := range req.Labels {
		labels[k] = v
	}

	return &networkingv1.Ingress{
		ObjectMeta: metav1.ObjectMeta{
			Name:      req.Name,
			Namespace: req.Namespace,
			Labels:    labels,
		},
		Spec: networkingv1.IngressSpec{
			Rules: []networkingv1.IngressRule{},
		},
	}
}

// addVSCodeIngressRule adds VSCode-specific ingress rule
func (c *Controller) addVSCodeIngressRule(ingress *networkingv1.Ingress, req *devmachines.CreateDevMachineRequest) {
	if req.WebIDE != devmachines.IDETypeVSCode {
		return
	}

	vscodeHost := fmt.Sprintf("/%s-%s(/|$)(.*)", req.Namespace, req.Name)
	pathType := networkingv1.PathTypePrefix
	ingress.Annotations = map[string]string{
		"nginx.ingress.kubernetes.io/rewrite-target": "/$2",
	}
	ingress.Spec.Rules = append(ingress.Spec.Rules, networkingv1.IngressRule{
		//Host: vscodeHost,
		IngressRuleValue: networkingv1.IngressRuleValue{
			HTTP: &networkingv1.HTTPIngressRuleValue{
				Paths: []networkingv1.HTTPIngressPath{
					{
						Path:     vscodeHost,
						PathType: &pathType,
						Backend: networkingv1.IngressBackend{
							Service: &networkingv1.IngressServiceBackend{
								Name: req.Name,
								Port: networkingv1.ServiceBackendPort{
									Number: vscodePort,
								},
							},
						},
					},
				},
			},
		},
	})
}

// addJupyterIngressRule adds Jupyter-specific ingress rule
func (c *Controller) addJupyterIngressRule(ingress *networkingv1.Ingress, req *devmachines.CreateDevMachineRequest) {
	if req.WebIDE != devmachines.IDETypeJupyter {
		return
	}

	jupyterHost := fmt.Sprintf("/%s-%s", req.Namespace, req.Name)
	pathType := networkingv1.PathTypePrefix

	ingress.Spec.Rules = append(ingress.Spec.Rules, networkingv1.IngressRule{
		//Host: jupyterHost,
		IngressRuleValue: networkingv1.IngressRuleValue{
			HTTP: &networkingv1.HTTPIngressRuleValue{
				Paths: []networkingv1.HTTPIngressPath{
					{
						Path:     jupyterHost,
						PathType: &pathType,
						Backend: networkingv1.IngressBackend{
							Service: &networkingv1.IngressServiceBackend{
								Name: req.Name,
								Port: networkingv1.ServiceBackendPort{
									Number: jupyterPort,
								},
							},
						},
					},
				},
			},
		},
	})
}

func (c *Controller) convertDeploymentToDevMachine(deployment *appsv1.Deployment) (*devmachines.DevMachine, error) {
	if len(deployment.Spec.Template.Spec.Containers) == 0 {
		return nil, fmt.Errorf("deployment %s/%s has no containers", deployment.Namespace, deployment.Name)
	}
	container := deployment.Spec.Template.Spec.Containers[0]
	envMap := make(map[string]string)
	for _, env := range container.Env {
		envMap[env.Name] = env.Value
	}
	machine := &devmachines.DevMachine{
		CreateDevMachineRequest: devmachines.CreateDevMachineRequest{
			Namespace:       deployment.Namespace,
			Name:            deployment.Name,
			Image:           container.Image,
			CPU:             container.Resources.Limits.Cpu().String(),
			Memory:          container.Resources.Limits.Memory().String(),
			Labels:          deployment.Labels,
			Annotations:     deployment.Annotations,
			EnvironmentVars: envMap,
		},
	}
	// Get creation time
	machine.CreatedAt = deployment.CreationTimestamp.Time.Format(time.DateTime)
	// Get last updated time from deployment status
	if len(deployment.Status.Conditions) > 0 {
		machine.LastUpdated = deployment.Status.Conditions[0].LastUpdateTime.Time.Format(time.DateTime)
	}
	// Get pod status
	pods, err := c.client.CoreV1().Pods(deployment.Namespace).List(context.Background(), metav1.ListOptions{
		LabelSelector: fmt.Sprintf("devmachine.tap.ai.com/name=%s", deployment.Name),
	})
	if err != nil && !errors.IsNotFound(err) {
		machine.Status = devmachines.StatusError
		return machine, fmt.Errorf("failed to get pods for deployment %s/%s: %w", deployment.Namespace, deployment.Name, err)
	}

	if pods == nil {
		pods = &corev1.PodList{Items: []corev1.Pod{}}
	}

	if deployment.Spec.Replicas != nil && *deployment.Spec.Replicas == 0 {
		if len(pods.Items) == 0 {
			machine.Status = devmachines.StatusStopped
		} else {
			machine.Status = devmachines.StatusTerminating
		}
		return machine, nil
	}

	// Handle case when no pods exist but replicas > 0
	if len(pods.Items) == 0 {
		machine.Status = devmachines.StatusUnknown
		return machine, nil
	}

	// Find the most recent pod for status details
	var targetPod *corev1.Pod
	for i := range pods.Items {
		pod := &pods.Items[i]
		if targetPod == nil || pod.CreationTimestamp.After(targetPod.CreationTimestamp.Time) {
			targetPod = pod
		}
	}

	if targetPod != nil {
		machine.PodName = targetPod.Name
		machine.NodeName = targetPod.Spec.NodeName
		machine.PodStatus = string(targetPod.Status.Phase)
		machine.Status = podStatus(targetPod)
	}
	return machine, nil
}

func podStatus(targetPod *corev1.Pod) string {
	var status string
	// 检查 Pod 是否正在删除中（Terminating）
	if targetPod.DeletionTimestamp != nil {
		status = devmachines.StatusTerminating
	} else {
		// Set machine status based on pod status
		switch targetPod.Status.Phase {
		case corev1.PodPending:
			// 检查是否有容器启动失败
			if hasCrashLoopBackOff(targetPod) {
				status = devmachines.StatusCrashLoopBackOff
			} else {
				status = devmachines.StatusPending
			}
		case corev1.PodRunning:
			// Check if all containers are ready
			allContainersReady := true
			for _, containerStatus := range targetPod.Status.ContainerStatuses {
				if !containerStatus.Ready {
					allContainersReady = false
					// 检查是否有容器处于 Crash 状态
					if isContainerCrashing(containerStatus) {
						status = devmachines.StatusCrashLoopBackOff
						break
					}
				}
			}
			if allContainersReady {
				status = devmachines.StatusRunning
			}
		case corev1.PodSucceeded:
			status = devmachines.StatusStopped
		case corev1.PodFailed:
			// 区分普通失败和 CrashLoopBackOff
			if hasCrashLoopBackOff(targetPod) {
				status = devmachines.StatusCrashLoopBackOff
			} else {
				status = devmachines.StatusError
			}
		case corev1.PodUnknown:
			status = devmachines.StatusUnknown
		default:
			status = devmachines.StatusUnknown
		}
	}
	return status
}

// 辅助函数：检查 Pod 是否有容器处于 CrashLoopBackOff 状态
func hasCrashLoopBackOff(pod *corev1.Pod) bool {
	for _, containerStatus := range pod.Status.ContainerStatuses {
		if isContainerCrashing(containerStatus) {
			return true
		}
	}
	return false
}

// 辅助函数：检查单个容器是否处于 Crash 状态
func isContainerCrashing(containerStatus corev1.ContainerStatus) bool {
	if containerStatus.State.Waiting != nil {
		return containerStatus.State.Waiting.Reason == "CrashLoopBackOff"
	}
	return false
}

// isImagePullError 判断 waiting reason 是否为镜像拉取失败
func isImagePullError(reason string) bool {
	return reason == "ImagePullBackOff" || reason == "ErrImagePull"
}

// computeLifecycleStage 根据 Pod 当前状态计算精细的生命周期阶段。
// Pod 正常生命周期：调度(Scheduling) → 拉取镜像(PullingImage) → InitContainer(Initializing) → 业务容器启动(Starting) → 运行(Running)
// 每个阶段都可能因不同原因失败，healthy=false 表示该阶段出现异常。
func computeLifecycleStage(pod *corev1.Pod) devmachines.LifecycleStageInfo {
	// 1. Pod 正在被删除
	if pod.DeletionTimestamp != nil {
		return devmachines.LifecycleStageInfo{
			Stage:   devmachines.StageTerminating,
			Healthy: true,
			Message: "Pod 正在终止",
		}
	}

	switch pod.Status.Phase {
	case corev1.PodPending:
		return computePendingStage(pod)

	case corev1.PodRunning:
		return computeRunningStage(pod)

	case corev1.PodSucceeded:
		return devmachines.LifecycleStageInfo{
			Stage:   devmachines.StageStopped,
			Healthy: true,
			Message: "Pod 已正常退出",
		}

	case corev1.PodFailed:
		reason, message := podFailureInfo(pod)
		return devmachines.LifecycleStageInfo{
			Stage:   devmachines.StageFailed,
			Healthy: false,
			Reason:  reason,
			Message: message,
		}

	default:
		return devmachines.LifecycleStageInfo{
			Stage:   devmachines.StageScheduling,
			Healthy: false,
			Reason:  "Unknown",
			Message: "Pod 状态未知",
		}
	}
}

// computePendingStage 处理 Pod Phase 为 Pending 时的阶段判断。
// Pending 可能处于：等待调度、拉取镜像、启动 InitContainer、启动业务容器 等子阶段。
func computePendingStage(pod *corev1.Pod) devmachines.LifecycleStageInfo {
	// 检查调度条件：PodScheduled=False 说明还未调度到节点
	for _, cond := range pod.Status.Conditions {
		if cond.Type == corev1.PodScheduled && cond.Status == corev1.ConditionFalse {
			return devmachines.LifecycleStageInfo{
				Stage:   devmachines.StageScheduling,
				Healthy: false,
				Reason:  cond.Reason,
				Message: cond.Message,
			}
		}
	}

	// 已调度到节点，检查 InitContainer 状态
	for _, cs := range pod.Status.InitContainerStatuses {
		if cs.State.Waiting != nil {
			reason := cs.State.Waiting.Reason
			msg := cs.State.Waiting.Message
			if isImagePullError(reason) {
				return devmachines.LifecycleStageInfo{
					Stage:   devmachines.StagePullingImage,
					Healthy: false,
					Reason:  reason,
					Message: fmt.Sprintf("InitContainer %s 镜像拉取失败: %s", cs.Name, msg),
				}
			}
			return devmachines.LifecycleStageInfo{
				Stage:   devmachines.StageInitializing,
				Healthy: reason == "PodInitializing" || reason == "ContainerCreating",
				Reason:  reason,
				Message: fmt.Sprintf("InitContainer %s 等待中: %s", cs.Name, msg),
			}
		}
		// InitContainer 运行中但尚未完成
		if cs.State.Running != nil && !cs.Ready {
			return devmachines.LifecycleStageInfo{
				Stage:   devmachines.StageInitializing,
				Healthy: true,
				Message: fmt.Sprintf("InitContainer %s 正在运行", cs.Name),
			}
		}
	}

	// 检查主容器等待状态
	for _, cs := range pod.Status.ContainerStatuses {
		if cs.State.Waiting != nil {
			reason := cs.State.Waiting.Reason
			msg := cs.State.Waiting.Message
			if isImagePullError(reason) {
				return devmachines.LifecycleStageInfo{
					Stage:   devmachines.StagePullingImage,
					Healthy: false,
					Reason:  reason,
					Message: fmt.Sprintf("容器 %s 镜像拉取失败: %s", cs.Name, msg),
				}
			}
			return devmachines.LifecycleStageInfo{
				Stage:   devmachines.StageStarting,
				Healthy: reason == "ContainerCreating" || reason == "PodInitializing",
				Reason:  reason,
				Message: fmt.Sprintf("容器 %s 等待中: %s", cs.Name, msg),
			}
		}
	}

	// Pod 已调度但无容器状态信息，正在准备中
	return devmachines.LifecycleStageInfo{
		Stage:   devmachines.StageScheduling,
		Healthy: true,
		Message: "Pod 已调度，正在准备容器",
	}
}

// computeRunningStage 处理 Pod Phase 为 Running 时的阶段判断。
// Running 阶段可能处于：InitContainer 收尾、业务容器启动、全部就绪 等子状态。
func computeRunningStage(pod *corev1.Pod) devmachines.LifecycleStageInfo {
	// 检查 InitContainer 是否仍在运行（Running phase 也可能有 init 未完成）
	for _, cs := range pod.Status.InitContainerStatuses {
		if !cs.Ready {
			if cs.State.Waiting != nil {
				reason := cs.State.Waiting.Reason
				if isImagePullError(reason) {
					return devmachines.LifecycleStageInfo{
						Stage:   devmachines.StagePullingImage,
						Healthy: false,
						Reason:  reason,
						Message: fmt.Sprintf("InitContainer %s 镜像拉取失败", cs.Name),
					}
				}
				return devmachines.LifecycleStageInfo{
					Stage:   devmachines.StageInitializing,
					Healthy: false,
					Reason:  reason,
					Message: fmt.Sprintf("InitContainer %s 异常: %s", cs.Name, cs.State.Waiting.Message),
				}
			}
			return devmachines.LifecycleStageInfo{
				Stage:   devmachines.StageInitializing,
				Healthy: true,
				Message: fmt.Sprintf("InitContainer %s 正在运行", cs.Name),
			}
		}
	}

	// 检查主容器就绪状态
	for _, cs := range pod.Status.ContainerStatuses {
		if cs.Ready {
			continue
		}
		if cs.State.Waiting != nil {
			reason := cs.State.Waiting.Reason
			msg := cs.State.Waiting.Message
			if isImagePullError(reason) {
				return devmachines.LifecycleStageInfo{
					Stage:   devmachines.StagePullingImage,
					Healthy: false,
					Reason:  reason,
					Message: fmt.Sprintf("容器 %s 镜像拉取失败: %s", cs.Name, msg),
				}
			}
			healthy := reason == "ContainerCreating" || reason == "PodInitializing"
			return devmachines.LifecycleStageInfo{
				Stage:   devmachines.StageStarting,
				Healthy: healthy,
				Reason:  reason,
				Message: fmt.Sprintf("容器 %s 启动中: %s", cs.Name, msg),
			}
		}
		// 容器未就绪且无等待原因，可能刚启动
		return devmachines.LifecycleStageInfo{
			Stage:   devmachines.StageStarting,
			Healthy: true,
			Message: fmt.Sprintf("容器 %s 正在启动，等待就绪", cs.Name),
		}
	}

	// 所有容器就绪
	return devmachines.LifecycleStageInfo{
		Stage:   devmachines.StageRunning,
		Healthy: true,
		Message: "所有容器正常运行",
	}
}

// podFailureInfo 从 Failed 的 Pod 中提取失败原因和消息
func podFailureInfo(pod *corev1.Pod) (reason, message string) {
	reason = pod.Status.Reason
	message = pod.Status.Message
	// 优先从容器状态中取更具体的错误
	for _, cs := range pod.Status.ContainerStatuses {
		if cs.State.Terminated != nil && cs.State.Terminated.ExitCode != 0 {
			if cs.State.Terminated.Reason != "" {
				reason = cs.State.Terminated.Reason
			}
			if cs.State.Terminated.Message != "" {
				message = fmt.Sprintf("容器 %s 异常退出(exit %d): %s", cs.Name, cs.State.Terminated.ExitCode, cs.State.Terminated.Message)
			} else {
				message = fmt.Sprintf("容器 %s 异常退出(exit %d)", cs.Name, cs.State.Terminated.ExitCode)
			}
			return
		}
		if cs.State.Waiting != nil && cs.State.Waiting.Reason == "CrashLoopBackOff" {
			reason = "CrashLoopBackOff"
			message = fmt.Sprintf("容器 %s 反复崩溃重启", cs.Name)
			return
		}
	}
	if message == "" {
		message = "Pod 运行失败"
	}
	return
}

// Helper function to check if a container has a specific port
func hasPort(ports []corev1.ContainerPort, portName string) bool {
	for _, port := range ports {
		if port.Name == portName {
			return true
		}
	}
	return false
}

// enrichDevMachineInfo adds additional information to the DevMachine object
func (c *Controller) enrichDevMachineInfo(ctx context.Context, machine *devmachines.DevMachine, namespace, name string) {
	// TODO： 更新列表状态
	pods, err := c.client.CoreV1().Pods(namespace).List(ctx, metav1.ListOptions{
		LabelSelector: fmt.Sprintf("app=%s", name),
	})
	if err == nil && len(pods.Items) > 0 {
		pod := pods.Items[0]
		machine.PodName = pod.Name
		machine.NodeName = pod.Spec.NodeName
		machine.PodStatus = string(pod.Status.Phase)
	}
}

