   429→func (c *Controller) WebTerminal(ctx *gin.Context, req *devmachines.DevMachineRequest) error {
   430→	dm := &db.DevMachines{Id: req.Id}
   431→	err := dm.Get(c.db)
   432→	if err != nil {
   433→		log.Errorf("get dev machine failed: %v", err)
   434→		return err
   435→	}
   436→	devMachine, err := c.getDevMachineFromApiserver(dm.ClusterCode, util.GetProjectDefaultNamespace(req.ProjectId), util.GetDevMachineName(dm.Id))
   437→	if err != nil {
   438→		log.Errorf("get dev machine from apiserver failed: %v", err)
   439→		return err
   440→	}
   441→	if devMachine.Status != devmachines.StatusRunning {
   442→		err = fmt.Errorf("devmachine %s is not running", dm.Name)
   443→		log.Error(err)
   444→		return err
   445→	}
   446→	var upgrader = websocket.Upgrader{
   447→		CheckOrigin: func(r *http.Request) bool {
   448→			return true
   449→		},
   450→	}
   451→	conn, err := upgrader.Upgrade(ctx.Writer, ctx.Request, nil)
   452→	if err != nil {
   453→		log.Errorf("webSocket upgrade Error:%v", err)
   454→		return err
   455→	}
   456→	log.Info("upgraded websocket.")
   457→	err = c.getter.ExecTerminal(conn, dm.ClusterCode, devMachine.Namespace, devMachine.PodName, "", "/bin/bash")
   458→	if err != nil {
   459→		log.Errorf("terminal failed: %v", err)
   460→		return err
   461→	}
   462→	return nil
   463→}
