   490→	project := &db.Project{Id: req.ProjectId}
   491→	if err := project.GetProjectById(c.db); err != nil {
   492→		log.Errorf("get project failed for machine %s: %v", req.ProjectId, err)
   493→		return nil, err
   494→	}
   495→	namespace := util.GetProjectDefaultNamespace(req.ProjectId)
   496→
   497→	var (
   498→		total    int64
   499→		machines []db.DevMachines
   500→		items    []devmachines.DevMachineListItem
   501→		err      error
   502→	)
   503→
   504→	// 根据状态参数选择不同的查询方式
   505→	if len(req.Status) == 0 {
   506→		// 状态为空时，直接分页查询
   507→		total, machines, err = dbDevMachines.List(c.db, req.Current, req.Size, true)
   508→		if err != nil {
   509→			log.Errorf("list dev machines failed: %v", err)
   510→			return nil, err
   511→		}
   512→	} else {
   513→		// 状态不为空时，获取全量数据
   514→		_, allMachines, err := dbDevMachines.List(c.db, 0, 0, true)
   515→		if err != nil {
   516→			log.Errorf("list all dev machines failed: %v", err)
   517→			return nil, err
   518→		}
   519→
   520→		// 并行获取所有开发机状态
   521→		var wg sync.WaitGroup
   522→		var mu sync.Mutex
   523→		allItems := make([]devmachines.DevMachineListItem, 0, len(allMachines))
   524→
   525→		for _, machine := range allMachines {
   526→			wg.Add(1)
   527→			go func(m db.DevMachines) {
   528→				defer wg.Done()
   529→
   530→				// 解析存储配置
   531→				storageConfigs := make([]models.StorageConfig, 0)
   532→				if err := json.Unmarshal([]byte(m.StorageConfigs), &storageConfigs); err != nil {
   533→					log.Errorf("unmarshal storage configs failed for machine %d: %v", m.Id, err)
   534→					// 不返回错误，继续处理其他机器
   535→					return
   536→				}
   537→
   538→				item := devmachines.DevMachineListItem{
   539→					Id:          m.Id,
   540→					Name:        m.Name,
   541→					ClusterCode: m.ClusterCode,
   542→					ClusterName: m.Cluster.Name,
   543→					QueueName:   m.QueueName,
   544→					CPU:         m.CPU,
   545→					Memory:      m.Memory,
   546→					GPU:         m.GPU,
   547→					ProjectName: project.Name,
   548→					Creator:     m.UserName,
   549→					WebURL:      m.WebURL,
   550→					Storage:     storageConfigs,
   551→					CreatedAt:   m.CreatedAt.Format(time.DateTime),
   552→				}
   553→
   554→				// 获取开发机状态
   555→				devmachineStatus, _ := c.getDevMachineFromApiserver(req.ClusterCode, namespace, util.GetDevMachineName(m.Id))
   556→				item.Status = devmachines.StatusUnknown
   557→				if devmachineStatus != nil && len(devmachineStatus.Status) > 0 {
   558→					item.Status = devmachineStatus.Status
   559→				}
   560→
   561→				mu.Lock()
   562→				allItems = append(allItems, item)
   563→				mu.Unlock()
   564→			}(machine)
   565→		}
   566→		wg.Wait()
   567→
   568→		// 过滤出符合状态要求的开发机
   569→		filteredItems := make([]devmachines.DevMachineListItem, 0)
   570→		for _, item := range allItems {
   571→			if item.Status == req.Status {
   572→				filteredItems = append(filteredItems, item)
   573→			}
   574→		}
   575→
   576→		// 手动分页
   577→		total = int64(len(filteredItems))
   578→		start := (req.Current - 1) * req.Size
   579→		if start < 0 {
   580→			start = 0
   581→		}
   582→		if start >= int(total) {
   583→			return &devmachines.ListDevMachineResponse{
   584→				Total: total,
   585→				Items: []devmachines.DevMachineListItem{},
   586→			}, nil
   587→		}
   588→
   589→		end := start + req.Size
   590→		if end > int(total) {
   591→			end = int(total)
   592→		}
   593→
   594→		items = filteredItems[start:end]
   595→	}
   596→
   597→	// 构建响应
   598→	response := &devmachines.ListDevMachineResponse{
   599→		Total: total,
   600→		Items: make([]devmachines.DevMachineListItem, 0),
   601→	}
   602→
   603→	// 处理状态为空的情况
   604→	if len(req.Status) == 0 {
   605→		// 并行获取开发机状态
   606→		var wg sync.WaitGroup
   607→		var mu sync.Mutex
   608→		items = make([]devmachines.DevMachineListItem, len(machines))
   609→
   610→		for i, machine := range machines {
   611→			wg.Add(1)
   612→			go func(index int, m db.DevMachines) {
   613→				defer wg.Done()
   614→
   615→				// 解析存储配置
   616→				storageConfigs := make([]models.StorageConfig, 0)
   617→				if err := json.Unmarshal([]byte(m.StorageConfigs), &storageConfigs); err != nil {
   618→					log.Errorf("unmarshal storage configs failed for machine %d: %v", m.Id, err)
   619→					// 不返回错误，继续处理其他机器
   620→					return
   621→				}
   622→
   623→				item := devmachines.DevMachineListItem{
   624→					Id:          m.Id,
   625→					Name:        m.Name,
   626→					ClusterCode: m.ClusterCode,
   627→					ClusterName: m.Cluster.Name,
   628→					QueueName:   m.QueueName,
   629→					CPU:         m.CPU,
   630→					Memory:      m.Memory,
   631→					GPU:         m.GPU,
   632→					ProjectName: project.Name,
   633→					Creator:     m.UserName,
   634→					WebURL:      m.WebURL,
   635→					Storage:     storageConfigs,
   636→					CreatedAt:   m.CreatedAt.Format(time.DateTime),
   637→				}
   638→
   639→				// 获取开发机状态
   640→				devmachineStatus, _ := c.getDevMachineFromApiserver(req.ClusterCode, namespace, util.GetDevMachineName(m.Id))
   641→				if devmachineStatus != nil {
   642→					item.Status = devmachineStatus.Status
   643→				} else {
   644→					item.Status = devmachines.StatusUnknown // 未知状态
   645→				}
   646→
   647→				mu.Lock()
   648→				items[index] = item
   649→				mu.Unlock()
   650→			}(i, machine)
   651→		}
   652→		wg.Wait()
   653→	}
