    29→// CreateDevMachine creates a new development machine
    30→func (c *Controller) CreateDevMachine(ctx context.Context, req *devmachines.CreateDevMachineRequest) (*devmachines.CreateDevMachineResponse, error) {
    31→	// Check if machine already exists
    32→	_, err := c.client.AppsV1().Deployments(req.Namespace).Get(ctx, req.Name, metav1.GetOptions{})
    33→	if err == nil {
    34→		return nil, fmt.Errorf("dev machine %s already exists", req.Name)
    35→	}
    36→	if !errors.IsNotFound(err) {
    37→		return nil, err
    38→	}
    39→
    40→	// Create deployment
    41→	// Create deployment with GPU resource if requested
    42→	deployment := c.createDevMachineDeployment(req)
    43→	if IsAscend910bDeployment(deployment) {
    44→		if err := DeploymentAscendConfig(c.client, deployment); err != nil {
    45→			return nil, err
    46→		}
    47→	}
    48→	_, err = c.client.AppsV1().Deployments(req.Namespace).Create(ctx, deployment, metav1.CreateOptions{})
    49→	if err != nil {
    50→		return nil, err
    51→	}
    52→
    53→	// Create service
    54→	service := c.createDevMachineService(req)
    55→	service, err = c.client.CoreV1().Services(req.Namespace).Create(ctx, service, metav1.CreateOptions{})
    56→	if err != nil {
    57→		return nil, err
    58→	}
    59→
    60→	// Create ingress if WebIDE is enabled
    61→	var webURL string
    62→	if strings.TrimSpace(req.WebIDE) != "" {
    63→		ingress := c.createDevMachineIngress(req)
    64→		ingress, err = c.client.NetworkingV1().Ingresses(req.Namespace).Create(ctx, ingress, metav1.CreateOptions{})
    65→		if err != nil {
    66→			return nil, err
    67→		}
    68→
    69→		// Get ingress URLs
    70→		if len(ingress.Spec.Rules) > 0 {
    71→			switch req.WebIDE {
    72→			case devmachines.IDETypeVSCode:
    73→				webURL = fmt.Sprintf(c.ingressAddress+"/%s-%s/vscode", req.Namespace, req.Name)
    74→			case devmachines.IDETypeJupyter:
    75→				webURL = fmt.Sprintf(c.ingressAddress+"%s?token=my-token", ingress.Spec.Rules[0].IngressRuleValue.HTTP.Paths[0].Path)
    76→			}
    77→		}
    78→	}
    79→
    80→	return &devmachines.CreateDevMachineResponse{
    81→		Name:        req.Name,
    82→		Status:      devmachines.StatusCreating,
    83→		WebURL:      webURL,
    84→		SSHEndpoint: fmt.Sprintf("%s:%d", service.Spec.ClusterIP, sshPort),
    85→		CreatedAt:   time.Now().Format("2006-01-02 15:04:05"),
    86→	}, nil
    87→}
