   198→// ListDevMachines lists all development machines in a namespace with pagination
   199→func (c *Controller) ListDevMachines(ctx context.Context, req *devmachines.ListDevMachinesRequest) (*devmachines.DevMachineList, error) {
   200→	// Use label selector if provided, otherwise use default
   201→	labelSelector := devMachineLabel
   202→	// if req.LabelSelector != "" {
   203→	// 	labelSelector = req.LabelSelector
   204→	// }
   205→
   206→	deployments, err := c.client.AppsV1().Deployments(req.ProjectName).List(ctx, metav1.ListOptions{
   207→		LabelSelector: labelSelector,
   208→	})
   209→	if err != nil {
   210→		return nil, err
   211→	}
   212→
   213→	// Get all machines first
   214→	var allMachines []devmachines.DevMachine
   215→	for _, deployment := range deployments.Items {
   216→		machine, err := c.convertDeploymentToDevMachine(&deployment)
   217→		if err != nil {
   218→			return nil, err
   219→		}
   220→
   221→		// Fetch additional information for each machine
   222→		c.enrichDevMachineInfo(ctx, machine, deployment.Namespace, deployment.Name)
   223→		allMachines = append(allMachines, *machine)
   224→	}
   225→
   226→	// Apply pagination
   227→	totalCount := int64(len(allMachines))
   228→
   229→	// Default values for pagination if not provided
   230→	page := int32(1)
   231→	pageSize := int32(10)
   232→
   233→	if req.Current > 0 {
   234→		page = int32(req.Current)
   235→	}
   236→	if req.Size > 0 && req.Size <= 100 {
   237→		pageSize = int32(req.Size)
   238→	}
   239→
   240→	// Calculate start and end indices for the current page
   241→	startIdx := (page - 1) * pageSize
   242→	endIdx := startIdx + pageSize
   243→
   244→	// Check bounds
   245→	if startIdx >= int32(totalCount) {
   246→		// Return empty page if start index is beyond total count
   247→		return &devmachines.DevMachineList{
   248→			Total: totalCount,
   249→			Page:  page,
   250→			Data:  []devmachines.DevMachine{},
   251→		}, nil
   252→	}
   253→
   254→	if endIdx > int32(totalCount) {
   255→		endIdx = int32(totalCount)
   256→	}
   257→
   258→	// Get the subset of machines for the current page
   259→	pagedMachines := allMachines[startIdx:endIdx]
   260→
   261→	return &devmachines.DevMachineList{
   262→		Total: totalCount,
   263→		Page:  page,
   264→		Data:  pagedMachines,
   265→	}, nil
   266→}
