   690→func (c *Controller) convertDeploymentToDevMachine(deployment *appsv1.Deployment) (*devmachines.DevMachine, error) {
   691→	if len(deployment.Spec.Template.Spec.Containers) == 0 {
   692→		return nil, fmt.Errorf("deployment %s/%s has no containers", deployment.Namespace, deployment.Name)
   693→	}
   694→	container := deployment.Spec.Template.Spec.Containers[0]
   695→	envMap := make(map[string]string)
   696→	for _, env := range container.Env {
   697→		envMap[env.Name] = env.Value
   698→	}
   699→	machine := &devmachines.DevMachine{
   700→		CreateDevMachineRequest: devmachines.CreateDevMachineRequest{
   701→			Namespace:       deployment.Namespace,
   702→			Name:            deployment.Name,
   703→			Image:           container.Image,
   704→			CPU:             container.Resources.Limits.Cpu().String(),
   705→			Memory:          container.Resources.Limits.Memory().String(),
   706→			Labels:          deployment.Labels,
   707→			Annotations:     deployment.Annotations,
   708→			EnvironmentVars: envMap,
   709→		},
   710→	}
   711→	// Get creation time
   712→	machine.CreatedAt = deployment.CreationTimestamp.Time.Format(time.DateTime)
   713→	// Get last updated time from deployment status
   714→	if len(deployment.Status.Conditions) > 0 {
   715→		machine.LastUpdated = deployment.Status.Conditions[0].LastUpdateTime.Time.Format(time.DateTime)
   716→	}
   717→	// Get pod status
   718→	pods, err := c.client.CoreV1().Pods(deployment.Namespace).List(context.Background(), metav1.ListOptions{
   719→		LabelSelector: fmt.Sprintf("devmachine.tap.ai.com/name=%s", deployment.Name),
   720→	})
   721→	if err != nil && !errors.IsNotFound(err) {
   722→		machine.Status = devmachines.StatusError
   723→		return machine, fmt.Errorf("failed to get pods for deployment %s/%s: %w", deployment.Namespace, deployment.Name, err)
   724→	}
   725→
   726→	if pods == nil {
   727→		pods = &corev1.PodList{Items: []corev1.Pod{}}
   728→	}
   729→
   730→	if deployment.Spec.Replicas != nil && *deployment.Spec.Replicas == 0 {
   731→		if len(pods.Items) == 0 {
   732→			machine.Status = devmachines.StatusStopped
   733→		} else {
   734→			machine.Status = devmachines.StatusTerminating
   735→		}
   736→		return machine, nil
   737→	}
   738→
   739→	// Handle case when no pods exist but replicas > 0
   740→	if len(pods.Items) == 0 {
   741→		machine.Status = devmachines.StatusUnknown
   742→		return machine, nil
   743→	}
   744→
   745→	// Find the most recent pod for status details
   746→	var targetPod *corev1.Pod
   747→	for i := range pods.Items {
   748→		pod := &pods.Items[i]
   749→		if targetPod == nil || pod.CreationTimestamp.After(targetPod.CreationTimestamp.Time) {
   750→			targetPod = pod
   751→		}
   752→	}
   753→
   754→	if targetPod != nil {
   755→		machine.PodName = targetPod.Name
   756→		machine.NodeName = targetPod.Spec.NodeName
   757→		machine.PodStatus = string(targetPod.Status.Phase)
   758→		machine.Status = podStatus(targetPod)
   759→	}
   760→	return machine, nil
   761→}
   762→
   763→func podStatus(targetPod *corev1.Pod) string {
   764→	var status string
   765→	// 检查 Pod 是否正在删除中（Terminating）
   766→	if targetPod.DeletionTimestamp != nil {
   767→		status = devmachines.StatusTerminating
   768→	} else {
   769→		// Set machine status based on pod status
   770→		switch targetPod.Status.Phase {
   771→		case corev1.PodPending:
   772→			// 检查是否有容器启动失败
   773→			if hasCrashLoopBackOff(targetPod) {
   774→				status = devmachines.StatusCrashLoopBackOff
   775→			} else {
   776→				status = devmachines.StatusPending
   777→			}
   778→		case corev1.PodRunning:
   779→			// Check if all containers are ready
   780→			allContainersReady := true
   781→			for _, containerStatus := range targetPod.Status.ContainerStatuses {
   782→				if !containerStatus.Ready {
   783→					allContainersReady = false
   784→					// 检查是否有容器处于 Crash 状态
   785→					if isContainerCrashing(containerStatus) {
   786→						status = devmachines.StatusCrashLoopBackOff
   787→						break
   788→					}
   789→				}
   790→			}
   791→			if allContainersReady {
   792→				status = devmachines.StatusRunning
   793→			}
   794→		case corev1.PodSucceeded:
   795→			status = devmachines.StatusStopped
   796→		case corev1.PodFailed:
   797→			// 区分普通失败和 CrashLoopBackOff
   798→			if hasCrashLoopBackOff(targetPod) {
   799→				status = devmachines.StatusCrashLoopBackOff
   800→			} else {
   801→				status = devmachines.StatusError
   802→			}
   803→		case corev1.PodUnknown:
   804→			status = devmachines.StatusUnknown
   805→		default:
   806→			status = devmachines.StatusUnknown
   807→		}
   808→	}
   809→	return status
   810→}
   811→
   812→// 辅助函数：检查 Pod 是否有容器处于 CrashLoopBackOff 状态
   813→func hasCrashLoopBackOff(pod *corev1.Pod) bool {
   814→	for _, containerStatus := range pod.Status.ContainerStatuses {
   815→		if isContainerCrashing(containerStatus) {
   816→			return true
   817→		}
   818→	}
   819→	return false
   820→}
   821→
   822→// 辅助函数：检查单个容器是否处于 Crash 状态
   823→func isContainerCrashing(containerStatus corev1.ContainerStatus) bool {
   824→	if containerStatus.State.Waiting != nil {
   825→		return containerStatus.State.Waiting.Reason == "CrashLoopBackOff"
   826→	}
   827→	return false
   828→}
