   362→func (c *Controller) configureResources(deployment *appsv1.Deployment, req *devmachines.CreateDevMachineRequest) error {
   363→	container := &deployment.Spec.Template.Spec.Containers[0]
   364→	// 创建新的资源列表，只保留 CPU 和内存资源
   365→	newLimits := corev1.ResourceList{}
   366→	newRequests := corev1.ResourceList{}
   367→
   368→	cpu, err := resource.ParseQuantity(req.CPU)
   369→	if err != nil {
   370→		return fmt.Errorf("invalid CPU quantity: %v", err)
   371→	}
   372→	newLimits[corev1.ResourceCPU] = cpu
   373→	newRequests[corev1.ResourceCPU] = cpu
   374→	memory, err := resource.ParseQuantity(req.Memory)
   375→	if err != nil {
   376→		return fmt.Errorf("invalid Memory quantity: %v", err)
   377→	}
   378→	newLimits[corev1.ResourceMemory] = memory
   379→	newRequests[corev1.ResourceMemory] = memory
   380→
   381→	if req.GPU != "" && req.GPUName != "" && req.GPUType != "" {
   382→		// TODO：这里暂时只考虑整卡，后续需要支持虚拟卡
   383→		// switch req.GPUType {
   384→		// case "1":
   385→		// 	// Add GPU resources
   386→		// 	container.Resources.Limits[gpuResource] = gpuQuantity
   387→		// 	container.Resources.Requests[gpuResource] = gpuQuantity
   388→		// case "2":
   389→		// default:
   390→		//}
   391→		gpuQuantity, err := resource.ParseQuantity(req.GPU)
   392→		if err != nil {
   393→			return fmt.Errorf("invalid GPU quantity: %v", err)
   394→		}
   395→		gpuResource := corev1.ResourceName(req.GPUName)
   396→		if len(gpuResource) != 0 {
   397→			newLimits[gpuResource] = gpuQuantity
   398→			newRequests[gpuResource] = gpuQuantity
   399→		}
   400→	}
   401→	container.Resources.Limits = newLimits
   402→	container.Resources.Requests = newRequests
   403→	return nil
   404→}
