   427→func (c *Controller) configureWebIDE(deployment *appsv1.Deployment, req *devmachines.CreateDevMachineRequest) {
   428→	if strings.TrimSpace(req.WebIDE) == "" {
   429→		return
   430→	}
   431→
   432→	container := &deployment.Spec.Template.Spec.Containers[0]
   433→	currentPorts := container.Ports // 只保留实际使用的ports变量
   434→
   435→	// 检查是否已经配置了相同的WebIDE
   436→	if c.hasSameWebIDEAlreadyConfigured(container, req.WebIDE) {
   437→		return
   438→	}
   439→
   440→	// 清除现有的WebIDE配置
   441→	c.clearWebIDEConfig(deployment)
   442→
   443→	// 配置新的WebIDE
   444→	switch req.WebIDE {
   445→	case devmachines.IDETypeVSCode:
   446→		container.Command = []string{
   447→			"/bin/bash", "-c",
   448→			fmt.Sprintf("code-server --bind-addr=0.0.0.0:%d --auth none", vscodePort),
   449→		}
   450→		container.Ports = append(currentPorts, corev1.ContainerPort{
   451→			Name:          "vscode",
   452→			ContainerPort: vscodePort,
   453→		})
   454→	case devmachines.IDETypeJupyter:
   455→		container.Command = []string{
   456→			"/bin/bash", "-c",
   457→			fmt.Sprintf("jupyter lab --ip=0.0.0.0 --port=8888 --allow-root --NotebookApp.token=my-token --ServerApp.base_url=/%s-%s", req.Namespace, req.Name),
   458→		}
   459→		container.Ports = append(currentPorts, corev1.ContainerPort{
   460→			Name:          "jupyter",
   461→			ContainerPort: jupyterPort,
   462→		})
   463→	}
   464→}
