   466→// 清除现有的WebIDE配置
   467→func (c *Controller) clearWebIDEConfig(deployment *appsv1.Deployment) {
   468→	container := &deployment.Spec.Template.Spec.Containers[0]
   469→
   470→	// 清除命令（只有当命令包含WebIDE相关命令时才清除）
   471→	if len(container.Command) > 0 {
   472→		commandStr := strings.Join(container.Command, " ")
   473→		if strings.Contains(commandStr, "code-server") || strings.Contains(commandStr, "jupyter lab") {
   474→			container.Command = nil
   475→		}
   476→	}
   477→
   478→	// 清除相关端口
   479→	newPorts := make([]corev1.ContainerPort, 0, len(container.Ports))
   480→	for _, port := range container.Ports {
   481→		if port.Name != "vscode" && port.Name != "jupyter" {
   482→			newPorts = append(newPorts, port)
   483→		}
   484→	}
   485→	container.Ports = newPorts
   486→}
