   488→// 检查是否已经配置了相同的WebIDE
   489→func (c *Controller) hasSameWebIDEAlreadyConfigured(container *corev1.Container, webIDE string) bool {
   490→	if len(container.Command) == 0 {
   491→		return false
   492→	}
   493→
   494→	commandStr := strings.Join(container.Command, " ")
   495→	switch webIDE {
   496→	case devmachines.IDETypeVSCode:
   497→		return strings.Contains(commandStr, "code-server")
   498→	case devmachines.IDETypeJupyter:
   499→		return strings.Contains(commandStr, "jupyter lab")
   500→	default:
   501→		return false
   502→	}
   503→}
