   505→func (c *Controller) configureEnvironmentVars(deployment *appsv1.Deployment, req *devmachines.CreateDevMachineRequest) {
   506→	if len(req.EnvironmentVars) == 0 {
   507→		return
   508→	}
   509→
   510→	container := &deployment.Spec.Template.Spec.Containers[0]
   511→
   512→	// 初始化环境变量切片（如果为nil）
   513→	if container.Env == nil {
   514→		container.Env = make([]corev1.EnvVar, 0, len(req.EnvironmentVars))
   515→	}
   516→
   517→	// 创建现有环境变量的映射以便快速查找
   518→	existingVars := make(map[string]int)
   519→	for i, env := range container.Env {
   520→		existingVars[env.Name] = i
   521→	}
   522→
   523→	// 处理请求中的环境变量
   524→	for name, value := range req.EnvironmentVars {
