func (s *DevMachinesTestSuite) TestComputeLifecycleStage() {
	now := metav1.Now()

	testCases := []struct {
		name            string
		pod             *corev1.Pod
		expectedStage   string
		expectedHealthy bool
		expectedReason  string
	}{
		{
			name: "Pod is terminating",
			pod: &corev1.Pod{
				ObjectMeta: metav1.ObjectMeta{DeletionTimestamp: &now},
				Status:     corev1.PodStatus{Phase: corev1.PodRunning},
			},
			expectedStage:   devmachines.StageTerminating,
			expectedHealthy: true,
		},
		{
			name: "Pod pending - unschedulable",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodPending,
					Conditions: []corev1.PodCondition{
						{
							Type:    corev1.PodScheduled,
							Status:  corev1.ConditionFalse,
							Reason:  "Unschedulable",
							Message: "0/3 nodes available: 3 Insufficient nvidia.com/gpu",
						},
					},
				},
			},
			expectedStage:   devmachines.StageScheduling,
			expectedHealthy: false,
			expectedReason:  "Unschedulable",
		},
		{
			name: "Pod pending - just scheduled, no container statuses",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodPending,
					Conditions: []corev1.PodCondition{
						{Type: corev1.PodScheduled, Status: corev1.ConditionTrue},
					},
				},
			},
			expectedStage:   devmachines.StageScheduling,
			expectedHealthy: true,
		},
		{
			name: "Pod pending - init container ImagePullBackOff",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodPending,
					InitContainerStatuses: []corev1.ContainerStatus{
						{
							Name: "init",
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{
									Reason:  "ImagePullBackOff",
									Message: "Back-off pulling image",
								},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StagePullingImage,
			expectedHealthy: false,
			expectedReason:  "ImagePullBackOff",
		},
		{
			name: "Pod pending - init container ErrImagePull",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodPending,
					InitContainerStatuses: []corev1.ContainerStatus{
						{
							Name: "init",
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{Reason: "ErrImagePull"},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StagePullingImage,
			expectedHealthy: false,
			expectedReason:  "ErrImagePull",
		},
		{
			name: "Pod pending - init container ContainerCreating",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodPending,
					InitContainerStatuses: []corev1.ContainerStatus{
						{
							Name: "init",
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{Reason: "ContainerCreating"},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StageInitializing,
			expectedHealthy: true,
			expectedReason:  "ContainerCreating",
		},
		{
			name: "Pod pending - init container running but not ready",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodPending,
					InitContainerStatuses: []corev1.ContainerStatus{
						{
							Name:  "init",
							Ready: false,
							State: corev1.ContainerState{
								Running: &corev1.ContainerStateRunning{},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StageInitializing,
			expectedHealthy: true,
		},
		{
			name: "Pod pending - main container ImagePullBackOff",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodPending,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name: "main",
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{
									Reason:  "ImagePullBackOff",
									Message: "Back-off pulling image",
								},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StagePullingImage,
			expectedHealthy: false,
			expectedReason:  "ImagePullBackOff",
		},
		{
			name: "Pod pending - main container ContainerCreating",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodPending,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name: "main",
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{Reason: "ContainerCreating"},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StageStarting,
			expectedHealthy: true,
			expectedReason:  "ContainerCreating",
		},
		{
			name: "Pod pending - main container CrashLoopBackOff",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodPending,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name: "main",
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{Reason: "CrashLoopBackOff"},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StageStarting,
			expectedHealthy: false,
			expectedReason:  "CrashLoopBackOff",
		},
		{
			name: "Pod running - all containers ready",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodRunning,
					ContainerStatuses: []corev1.ContainerStatus{
						{Name: "main", Ready: true},
						{Name: "sidecar", Ready: true},
					},
				},
			},
			expectedStage:   devmachines.StageRunning,
			expectedHealthy: true,
		},
		{
			name: "Pod running - init container still running",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodRunning,
					InitContainerStatuses: []corev1.ContainerStatus{
						{
							Name:  "init",
							Ready: false,
							State: corev1.ContainerState{Running: &corev1.ContainerStateRunning{}},
						},
					},
				},
			},
			expectedStage:   devmachines.StageInitializing,
			expectedHealthy: true,
		},
		{
			name: "Pod running - init container ImagePullBackOff",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodRunning,
					InitContainerStatuses: []corev1.ContainerStatus{
						{
							Name:  "init",
							Ready: false,
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{Reason: "ImagePullBackOff"},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StagePullingImage,
			expectedHealthy: false,
			expectedReason:  "ImagePullBackOff",
		},
		{
			name: "Pod running - main container ImagePullBackOff",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodRunning,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name:  "main",
							Ready: false,
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{Reason: "ImagePullBackOff"},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StagePullingImage,
			expectedHealthy: false,
			expectedReason:  "ImagePullBackOff",
		},
		{
			name: "Pod running - main container CrashLoopBackOff",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodRunning,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name:  "main",
							Ready: false,
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{
									Reason:  "CrashLoopBackOff",
									Message: "back-off restarting failed container",
								},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StageStarting,
			expectedHealthy: false,
			expectedReason:  "CrashLoopBackOff",
		},
		{
			name: "Pod running - container not ready, no waiting state",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodRunning,
					ContainerStatuses: []corev1.ContainerStatus{
						{Name: "main", Ready: false},
					},
				},
			},
			expectedStage:   devmachines.StageStarting,
			expectedHealthy: true,
		},
		{
			name: "Pod succeeded",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{Phase: corev1.PodSucceeded},
			},
			expectedStage:   devmachines.StageStopped,
			expectedHealthy: true,
		},
		{
			name: "Pod failed - OOMKilled",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase:   corev1.PodFailed,
					Reason:  "OOMKilled",
					Message: "Container killed due to OOM",
				},
			},
			expectedStage:   devmachines.StageFailed,
			expectedHealthy: false,
		},
		{
			name: "Pod failed - container CrashLoopBackOff",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodFailed,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name: "main",
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{Reason: "CrashLoopBackOff"},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StageFailed,
			expectedHealthy: false,
			expectedReason:  "CrashLoopBackOff",
		},
		{
			name: "Pod failed - container terminated with non-zero exit",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodFailed,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name: "main",
							State: corev1.ContainerState{
								Terminated: &corev1.ContainerStateTerminated{
									ExitCode: 1,
									Reason:   "Error",
									Message:  "process exited with code 1",
								},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StageFailed,
			expectedHealthy: false,
			expectedReason:  "Error",
		},
		{
			name: "Pod unknown phase",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{Phase: corev1.PodUnknown},
			},
			expectedStage:   devmachines.StageScheduling,
			expectedHealthy: false,
			expectedReason:  "Unknown",
		},
	}

	for _, tc := range testCases {
		s.Run(tc.name, func() {
			result := computeLifecycleStage(tc.pod)
			s.Equal(tc.expectedStage, result.Stage, "stage mismatch")
			s.Equal(tc.expectedHealthy, result.Healthy, "healthy mismatch")
			if tc.expectedReason != "" {
				s.Equal(tc.expectedReason, result.Reason, "reason mismatch")
			}
			s.NotEmpty(result.Message, "message should never be empty")
		})
	}
}

