			name: "Pod pending - main container ImagePullBackOff",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodPending,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name: "main",
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{
									Reason:  "ImagePullBackOff",
									Message: "Back-off pulling image",
								},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StagePullingImage,
			expectedHealthy: false,
			expectedReason:  "ImagePullBackOff",
		},
		{
			name: "Pod pending - main container ContainerCreating",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodPending,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name: "main",
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{Reason: "ContainerCreating"},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StageStarting,
			expectedHealthy: true,
			expectedReason:  "ContainerCreating",
		},
		{
			name: "Pod pending - main container CrashLoopBackOff",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodPending,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name: "main",
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{Reason: "CrashLoopBackOff"},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StageStarting,
			expectedHealthy: false,
			expectedReason:  "CrashLoopBackOff",
		},
		{
			name: "Pod running - all containers ready",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodRunning,
					ContainerStatuses: []corev1.ContainerStatus{
						{Name: "main", Ready: true},
