		{
			name: "Pod running - init container still running",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodRunning,
					InitContainerStatuses: []corev1.ContainerStatus{
						{
							Name:  "init",
							Ready: false,
							State: corev1.ContainerState{Running: &corev1.ContainerStateRunning{}},
						},
					},
				},
			},
			expectedStage:   devmachines.StageInitializing,
			expectedHealthy: true,
		},
		{
			name: "Pod running - init container ImagePullBackOff",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodRunning,
					InitContainerStatuses: []corev1.ContainerStatus{
						{
							Name:  "init",
							Ready: false,
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{Reason: "ImagePullBackOff"},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StagePullingImage,
			expectedHealthy: false,
			expectedReason:  "ImagePullBackOff",
		},
		{
			name: "Pod running - main container ImagePullBackOff",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodRunning,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name:  "main",
							Ready: false,
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{Reason: "ImagePullBackOff"},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StagePullingImage,
			expectedHealthy: false,
			expectedReason:  "ImagePullBackOff",
		},
		{
			name: "Pod running - main container CrashLoopBackOff",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodRunning,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name:  "main",
							Ready: false,
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{
									Reason:  "CrashLoopBackOff",
									Message: "back-off restarting failed container",
								},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StageStarting,
			expectedHealthy: false,
			expectedReason:  "CrashLoopBackOff",
		},
		{
			name: "Pod running - container not ready, no waiting state",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodRunning,
					ContainerStatuses: []corev1.ContainerStatus{
						{Name: "main", Ready: false},
					},
				},
			},
			expectedStage:   devmachines.StageStarting,
			expectedHealthy: true,
		},
		{
			name: "Pod succeeded",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{Phase: corev1.PodSucceeded},
			},
			expectedStage:   devmachines.StageStopped,
			expectedHealthy: true,
		},
		{
			name: "Pod failed - OOMKilled",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase:   corev1.PodFailed,
					Reason:  "OOMKilled",
					Message: "Container killed due to OOM",
				},
			},
			expectedStage:   devmachines.StageFailed,
			expectedHealthy: false,
		},
		{
			name: "Pod failed - container CrashLoopBackOff",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodFailed,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name: "main",
							State: corev1.ContainerState{
								Waiting: &corev1.ContainerStateWaiting{Reason: "CrashLoopBackOff"},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StageFailed,
			expectedHealthy: false,
			expectedReason:  "CrashLoopBackOff",
		},
		{
			name: "Pod failed - container terminated with non-zero exit",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{
					Phase: corev1.PodFailed,
					ContainerStatuses: []corev1.ContainerStatus{
						{
							Name: "main",
							State: corev1.ContainerState{
								Terminated: &corev1.ContainerStateTerminated{
									ExitCode: 1,
									Reason:   "Error",
									Message:  "process exited with code 1",
								},
							},
						},
					},
				},
			},
			expectedStage:   devmachines.StageFailed,
			expectedHealthy: false,
			expectedReason:  "Error",
		},
		{
			name: "Pod unknown phase",
			pod: &corev1.Pod{
				Status: corev1.PodStatus{Phase: corev1.PodUnknown},
			},
			expectedStage:   devmachines.StageScheduling,
			expectedHealthy: false,
			expectedReason:  "Unknown",
		},
	}

	for _, tc := range testCases {
		s.Run(tc.name, func() {
			result := computeLifecycleStage(tc.pod)
			s.Equal(tc.expectedStage, result.Stage, "stage mismatch")
			s.Equal(tc.expectedHealthy, result.Healthy, "healthy mismatch")
			if tc.expectedReason != "" {
				s.Equal(tc.expectedReason, result.Reason, "reason mismatch")
			}
			s.NotEmpty(result.Message, "message should never be empty")
		})
	}
}

func TestDevMachinesSuite(t *testing.T) {
	suite.Run(t, new(DevMachinesTestSuite))
}

