package controller

import (
	"context"
	"testing"

	"github.com/stretchr/testify/suite"
	appsv1 "k8s.io/api/apps/v1"
	corev1 "k8s.io/api/core/v1"
	networkingv1 "k8s.io/api/networking/v1"
	"k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes/fake"
	"k8s.io/utils/pointer"

	devmachines "code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/models/dev_machines"
)

type DevMachinesTestSuite struct {
	suite.Suite
	controller *Controller
	ctx        context.Context
}

func (s *DevMachinesTestSuite) SetupTest() {
	clientset := fake.NewSimpleClientset()
	s.controller = &Controller{
		client:           clientset,
		dynamicClient:    nil,
		monitoringClient: nil,
		volcanoClient:    nil,
		kedav2Client:     nil,
	}
	s.ctx = context.Background()
}

func (s *DevMachinesTestSuite) TestCreateDevMachine() {
	testCases := []struct {
		name        string
		req         *devmachines.CreateDevMachineRequest
		expectError bool
	}{
		{
			name: "Create basic dev machine",
			req: &devmachines.CreateDevMachineRequest{
				Name:      "test-machine-1",
				Namespace: "default",
				Image:     "ubuntu:latest",
				CPU:       "500m",
				Memory:    "500Mi",
				WebIDE:    devmachines.IDETypeVSCode,
				Labels: map[string]string{
					"env": "test",
				},
			},
			expectError: false,
		},
		{
			name: "Create dev machine with GPU",
			req: &devmachines.CreateDevMachineRequest{
				Name:      "test-machine-2",
				Namespace: "default",
				Image:     "nvidia/cuda:latest",
				CPU:       "500m",
				Memory:    "500Mi",
				GPU:       "1",
				GPUName:   "nvidia.com/gpu",
				GPUType:   "1",
				WebIDE:    devmachines.IDETypeJupyter,
			},
			expectError: false,
		},
		{
			name: "Create dev machine with invalid GPU type",
			req: &devmachines.CreateDevMachineRequest{
				Name:      "test-machine-3",
				Namespace: "default",
				Image:     "ubuntu:latest",
				CPU:       "500m",
				Memory:    "500Mi",
				GPU:       "1",
				GPUName:   "nvidia-tesla-v100",
				GPUType:   "3",
				WebIDE:    devmachines.IDETypeVSCode,
			},
			// TODO: 目前暂时不校验GPUType，后续需要增加虚拟卡类型，此处暂时设置为false
			expectError: false,
		},
	}

	for _, tc := range testCases {
		s.Run(tc.name, func() {
			resp, err := s.controller.CreateDevMachine(s.ctx, tc.req)
			if tc.expectError {
				s.Error(err)
				return
			}
			s.NoError(err)
			s.NotNil(resp)
			s.Equal(tc.req.Name, resp.Name)
			s.Equal(devmachines.StatusCreating, resp.Status)

			// Verify deployment was created
			deployment, err := s.controller.client.AppsV1().Deployments(tc.req.Namespace).Get(s.ctx, tc.req.Name, metav1.GetOptions{})
			s.NoError(err)
			s.NotNil(deployment)
			s.Equal(tc.req.Name, deployment.Name)
		})
	}

	// Test creating a dev machine that already exists
	_, err := s.controller.CreateDevMachine(s.ctx, testCases[0].req)
	s.Error(err)
}

func (s *DevMachinesTestSuite) TestUpdateDevMachine() {
	// Test cases for update
	testCases := []struct {
		name        string
		initial     *appsv1.Deployment
		updateReq   *devmachines.UpdateDevMachineRequest
		expectError bool
	}{
		{
			name: "Update non-existent machine",
			updateReq: &devmachines.UpdateDevMachineRequest{
				CreateDevMachineRequest: devmachines.CreateDevMachineRequest{
					Namespace: "default",
					Name:      "test-machine-2",
					CPU:       "500m",
					Memory:    "500Mi",
				},
			},
			expectError: true,
		},
		{
			name: "Update existing machine successfully",
			initial: &appsv1.Deployment{
				ObjectMeta: metav1.ObjectMeta{
					Name:      "test-machine-1",
					Namespace: "default",
					Labels: map[string]string{
						"app": "test-machine",
					},
				},
				Spec: appsv1.DeploymentSpec{
					Replicas: pointer.Int32(1),
					Selector: &metav1.LabelSelector{
						MatchLabels: map[string]string{
							"app": "test-machine",
						},
					},
					Template: corev1.PodTemplateSpec{
						ObjectMeta: metav1.ObjectMeta{
							Labels: map[string]string{
								"app": "test-machine",
							},
						},
						Spec: corev1.PodSpec{
							Containers: []corev1.Container{
								{
									Name:  "test-container",
									Image: "test-image",
								},
							},
						},
					},
				},
			},
			updateReq: &devmachines.UpdateDevMachineRequest{
				CreateDevMachineRequest: devmachines.CreateDevMachineRequest{
					Namespace: "default",
					Name:      "test-machine-1",
					CPU:       "1000m",
					Memory:    "1Gi",
					Labels: map[string]string{
						"env": "test",
					},
				},
			},
			expectError: false,
		},
	}

	for _, tc := range testCases {
		s.Run(tc.name, func() {
			// Create initial deployment if provided
			if tc.initial != nil {
				_, err := s.controller.client.AppsV1().Deployments(tc.initial.Namespace).Create(s.ctx, tc.initial, metav1.CreateOptions{})
				s.NoError(err)
			}

			// Perform update
			name := "test-machine-1"
			if tc.initial == nil {
				name = "non-existent"
			}

			resp, err := s.controller.UpdateDevMachine(s.ctx, name, "default", tc.updateReq)
			if tc.expectError {
				s.Error(err)
				return
			}

			s.NoError(err)
			s.NotNil(resp)
		})
	}
}

func (s *DevMachinesTestSuite) TestDeleteDevMachine() {
	// Create resources to delete
	deployment := &appsv1.Deployment{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-machine",
			Namespace: "default",
		},
	}
	service := &corev1.Service{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-machine",
			Namespace: "default",
		},
	}
	ingress := &networkingv1.Ingress{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-machine",
			Namespace: "default",
		},
	}

	_, err := s.controller.client.AppsV1().Deployments("default").Create(s.ctx, deployment, metav1.CreateOptions{})
	s.NoError(err)
	_, err = s.controller.client.CoreV1().Services("default").Create(s.ctx, service, metav1.CreateOptions{})
	s.NoError(err)
	_, err = s.controller.client.NetworkingV1().Ingresses("default").Create(s.ctx, ingress, metav1.CreateOptions{})
	s.NoError(err)

	// Test deleting the dev machine
	req := &devmachines.DevMachineRequest{}

	resp, err := s.controller.DeleteDevMachine(s.ctx, "test-machine", "default", req)
	s.NoError(err)
	s.NotNil(resp)

	// Verify resources were deleted
	_, err = s.controller.client.AppsV1().Deployments("default").Get(s.ctx, "test-machine", metav1.GetOptions{})
	s.True(errors.IsNotFound(err))

	_, err = s.controller.client.CoreV1().Services("default").Get(s.ctx, "test-machine", metav1.GetOptions{})
	s.True(errors.IsNotFound(err))

	_, err = s.controller.client.NetworkingV1().Ingresses("default").Get(s.ctx, "test-machine", metav1.GetOptions{})
	s.True(errors.IsNotFound(err))
}

func (s *DevMachinesTestSuite) TestStartStopDevMachine() {
	// Create initial deployment with 0 replicas
	var replicas int32 = 0
	deployment := &appsv1.Deployment{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-machine",
			Namespace: "default",
		},
		Spec: appsv1.DeploymentSpec{
			Replicas: &replicas,
		},
	}
	_, err := s.controller.client.AppsV1().Deployments("default").Create(s.ctx, deployment, metav1.CreateOptions{})
	s.NoError(err)

	// Test starting the dev machine
	startResp, err := s.controller.StartDevMachine(s.ctx, "default", "test-machine")
	s.NoError(err)
	s.NotNil(startResp)
	s.Equal(devmachines.StatusRunning, startResp.Status)

	// Verify deployment was started (replicas = 1)
	updatedDeployment, err := s.controller.client.AppsV1().Deployments("default").Get(s.ctx, "test-machine", metav1.GetOptions{})
	s.NoError(err)
	s.Equal(int32(1), *updatedDeployment.Spec.Replicas)

	// Test stopping the dev machine
	stopResp, err := s.controller.StopDevMachine(s.ctx, "default", "test-machine")
	s.NoError(err)
	s.NotNil(stopResp)
	s.Equal(devmachines.StatusStopped, stopResp.Status)

	// Verify deployment was stopped (replicas = 0)
	updatedDeployment, err = s.controller.client.AppsV1().Deployments("default").Get(s.ctx, "test-machine", metav1.GetOptions{})
	s.NoError(err)
	s.Equal(int32(0), *updatedDeployment.Spec.Replicas)
}

func (s *DevMachinesTestSuite) TestDeleteDevMachineNotFound() {
	// Test deleting a non-existent dev machine
	req := &devmachines.DevMachineRequest{
		ClusterCode: "default",
		ProjectId:   1,
		Name:        "non-existent-machine",
	}

	resp, err := s.controller.DeleteDevMachine(s.ctx, "non-existent-machine", "default", req)
	s.NoError(err)
	s.NotNil(resp)
}

func TestDevMachinesSuite(t *testing.T) {
	suite.Run(t, new(DevMachinesTestSuite))
}

