	"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/k8s"
)

var (
	client        kubernetes.Interface
	dynClient     dynamic.Interface
	kedav2Client  kedav2.Interface
	volcanoClient volcano.Interface
	controller    *k8scontroller.Controller
	err           error
	ctx           = context.Background()
	scheme        = runtime.NewScheme()

	gvrs = map[schema.GroupVersionResource]string{
		k8scontroller.GVRPrometheusRules: "PrometheusRulesList",
	}
)

func TestController(t *testing.T) {
	RegisterFailHandler(Fail)
	RunSpecs(t, "Controller Suite")
}

func addNodes(c kubernetes.Interface) {
	node1 := &corev1.Node{
		ObjectMeta: metav1.ObjectMeta{
			Name: "node1",
		},
		Spec: corev1.NodeSpec{
			Unschedulable: false,
		},
		Status: corev1.NodeStatus{
			Conditions: []corev1.NodeCondition{
				{
					Type:   corev1.NodeReady,
					Status: corev1.ConditionTrue,
				},
			},
		},
	}
	node2 := &corev1.Node{
		ObjectMeta: metav1.ObjectMeta{
			Name: "node2",
		},
		Spec: corev1.NodeSpec{
			Unschedulable: false,
		},
		Status: corev1.NodeStatus{
			Conditions: []corev1.NodeCondition{
				{
					Type:   corev1.NodeReady,
					Status: corev1.ConditionTrue,
				},
			},
		},
	}
	node3 := &corev1.Node{
		ObjectMeta: metav1.ObjectMeta{
			Name: "node3",
		},
		Spec: corev1.NodeSpec{
			Unschedulable: false,
		},
		Status: corev1.NodeStatus{
			Conditions: []corev1.NodeCondition{
				{
					Type:   corev1.NodeReady,
					Status: corev1.ConditionTrue,
				},
			},
		},
	}

	_, err = c.CoreV1().Nodes().Create(ctx, node1, metav1.CreateOptions{})
	Expect(err).NotTo(HaveOccurred())
	_, err = c.CoreV1().Nodes().Create(ctx, node2, metav1.CreateOptions{})
	Expect(err).NotTo(HaveOccurred())
	_, err = c.CoreV1().Nodes().Create(ctx, node3, metav1.CreateOptions{})
	Expect(err).NotTo(HaveOccurred())
}

var _ = BeforeSuite(func() {
	o := options.NewOptions()
	o.Log.Complete().SetUp()

	client = k8s.NewFakeClient()

	dynClient = fake.NewSimpleDynamicClientWithCustomListKinds(scheme, gvrs)
	monitoringClient := monitoringfake.NewSimpleClientset()
	volcanoClient := volcanofake.NewSimpleClientset()
	kedav2Client = kedav2fake.NewSimpleClientset()

	addNodes(client)

	controller, err = k8scontroller.NewController(&rest.Config{}, client, dynClient, monitoringClient, volcanoClient, kedav2Client, nil, "", k8scontroller.KubeEye{}, nil, nil)
	Expect(err).NotTo(HaveOccurred())
})

